import { useRef, useState, useCallback } from 'react';

interface MagnetProps {
  children: React.ReactNode;
  padding?: number;     // zona de ativação em px
  strength?: number;   // divisor — maior = movimento menor
  activeTransition?: string;
  inactiveTransition?: string;
}

export function Magnet({
  children,
  padding = 100,
  strength = 3,
  activeTransition = 'transform 0.3s ease-out',
  inactiveTransition = 'transform 0.6s ease-in-out',
}: MagnetProps) {
  const ref = useRef<HTMLDivElement>(null);
  const [style, setStyle] = useState({ transform: 'translate3d(0,0,0)', transition: inactiveTransition });

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!ref.current) return;
    const rect = ref.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const dx = e.clientX - centerX;
    const dy = e.clientY - centerY;
    const dist = Math.sqrt(dx * dx + dy * dy);
    const activation = Math.max(rect.width, rect.height) / 2 + padding;

    if (dist < activation) {
      setStyle({
        transform: `translate3d(${dx / strength}px, ${dy / strength}px, 0)`,
        transition: activeTransition,
      });
    } else {
      setStyle({
        transform: 'translate3d(0,0,0)',
        transition: inactiveTransition,
      });
    }
  }, [padding, strength, activeTransition, inactiveTransition]);

  const reset = useCallback(() => {
    setStyle({ transform: 'translate3d(0,0,0)', transition: inactiveTransition });
  }, [inactiveTransition]);

  return (
    <div
      ref={ref}
      onMouseMove={handleMouseMove as any}
      onMouseLeave={reset}
      style={{ ...style, willChange: 'transform', display: 'inline-block' }}
    >
      {children}
    </div>
  );
}
